public void modifiedFieldValue(FieldName _fieldName, int _arrayIndex)
{
    next  modifiedFieldValue(_fieldName, _arrayIndex);

    switch (_fieldName)
    {
        case fieldStr(ProdTable, ItemId):
            this.BOMId = '';
            break;

        case fieldStr(ProdTable, InventDimId):
            this.BOMId = '';
            break;

        case fieldStr(ProdTable, DlvDate):
            this.BOMId = '';
            break;

        case fieldStr(ProdTable,ETGQtySched):
            this.QtySched = this.ETGQtySched;
            break;

        case fieldStr(ProdTable,BOMId):
            this.BOMId = this.ETGBOMId1;
            break;
    }
}

public void insert(boolean _dropEstimated , Common _childBuffer , boolean _expandBOMRoute )
{
    this.PmfYieldPct = this.ETGPmfYieldPct;
    this.BOMId  = this.ETGBOMId1;
    this.QtySched = this.ETGQtySched;
    this.RemainInventPhysical = this.ETGQtySched;
    next insert( _dropEstimated , _childBuffer , _expandBOMRoute);


}

